 import { findTeam } from "./store.js";

+export class SeatLimitReachedError extends Error {
+  constructor(team, usage) {
+    super(`Team ${team.id} has reached its seat limit of ${team.seatLimit}. Add seats before inviting more members.`);
+    this.name = "SeatLimitReachedError";
+    this.code = "SEAT_LIMIT_REACHED";
+    this.teamId = team.id;
+    this.seatLimit = team.seatLimit;
+    this.seatUsage = usage;
+  }
+}
+
+export function getSeatUsage(store, teamId) {
+  const activeMembers = store.members.filter((member) => member.teamId === teamId).length;
+  const pendingInvites = store.invites.filter((invite) => invite.teamId === teamId && invite.status === "pending").length;
+
+  return activeMembers + pendingInvites;
+}
+
+export function hasSeatAvailable(store, teamId) {
+  const team = findTeam(store, teamId);
+
+  return team.seatLimit == null || getSeatUsage(store, teamId) < team.seatLimit;
+}
